      grid[nr][nc] = grid[r][c] + 1  // set distance
      queue.offer([nr, nc])           // mark visited`}),i.jsxs("div",{className:"mt-3 px-4 py-3 rounded-lg border text-xs leading-relaxed text-default-500",style:{background:`${it}0d`,borderColor:`${it}44`},children:[i.jsx("span",{style:{color:it},className:"font-bold",children:"⚠️ Key insight: "}),"No separate ",i.jsx("code",{children:"visited[][]"})," array needed! The act of writing a distance into a cell (replacing INF) ",i.jsx("em",{children:"is"})," the visited check. Walls (-1) are automatically skipped since -1 ≠ INF."]})]})}),i.jsx($,{children:i.jsxs(_,{children:[i.jsx("p",{className:"text-xs font-bold text-default-500 uppercase tracking-wider mb-3",children:"Complexity"}),i.jsx("div",{className:"flex gap-3 flex-wrap",children:[{l:"TIME",v:"O(m · n)",s:"Every cell enqueued and dequeued at most once"},{l:"SPACE",v:"O(m · n)",s:"BFS queue can hold up to all cells in the grid"}].map(({l:b,v:y,s:T})=>i.jsxs("div",{className:"flex-1 rounded-lg p-4 text-center",style:{background:"var(--viz-surface)",border:"1px solid var(--viz-border)"},children:[i.jsx("p",{className:"text-xs text-default-500 mb-1",children:b}),i.jsx("p",{className:"font-bold text-base",style:{color:Pe},children:y}),i.jsx("p",{className:"text-xs text-default-400 mt-1",children:T})]},b))})]})})]})},"Intuition"),i.jsx(Z,{title:"Visualizer",children:i.jsxs("div",{className:"flex flex-col gap-4 max-w-3xl mx-auto py-4 pb-10",children:[i.jsx($,{children:i.jsxs(_,{children:[i.jsx("p",{className:"text-xs font-bold text-default-500 uppercase tracking-wider mb-3",children:"Configure"}),i.jsx("div",{className:"flex gap-2 flex-wrap",children:aR.map((b,y)=>i.jsx(ee,{size:"sm",variant:a===y?"flat":"bordered",color:a===y?"primary":"default",onPress:()=>n(y),children:b.label},b.label))}),i.jsx("div",{className:"flex gap-4 mt-4 flex-wrap text-xs text-default-500",children:[{color:it,symbol:"💎",label:"Treasure (0)"},{color:"rgba(80,80,90,0.8)",symbol:"▪",label:"Wall (-1)"},{color:"var(--viz-muted)",symbol:"∞",lab